import { useState, useEffect } from "react";
import { LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Area, AreaChart } from "recharts";

const COLORS = {
  bg: "#0a0e17",
  card: "#111827",
  cardHover: "#1a2332",
  border: "#1e293b",
  accent: "#00d4aa",
  accentDim: "#00d4aa33",
  warning: "#f59e0b",
  danger: "#ef4444",
  text: "#e2e8f0",
  textDim: "#64748b",
  profit: "#00d4aa",
  loss: "#ef4444",
  gold: "#fbbf24",
  blue: "#3b82f6",
  purple: "#8b5cf6",
};

const initialChallenges = [
  { id: 1, date: "2026-03-20", firm: "Funding Pips", size: 50000, ea: "ORB_US30_v3", instrument: "US30", cost: 99, phase: "Phase 1", result: "En Curso", days: 0, maxDD: 2.1 },
  { id: 2, date: "2026-03-25", firm: "Funding Pips", size: 50000, ea: "Scalper_XAUUSD_v5", instrument: "XAUUSD", cost: 99, phase: "Phase 1", result: "Pendiente", days: 0, maxDD: 0 },
];

const initialEAs = [
  { name: "ORB_US30_v3", instrument: "US30", pf: 1.85, winRate: 62, maxDD: 4.2, trades: 342, sharpe: 1.4, status: "Producción" },
  { name: "Scalper_XAUUSD_v5", instrument: "XAUUSD", pf: 1.62, winRate: 58, maxDD: 5.1, trades: 289, sharpe: 1.1, status: "Testing" },
];

const monthlyData = [
  { month: "Mar", income: 0, expenses: 198, net: -198, capital: 4802 },
  { month: "Abr", income: 400, expenses: 50, net: 350, capital: 5152 },
  { month: "May", income: 800, expenses: 99, net: 701, capital: 5853 },
  { month: "Jun", income: 1200, expenses: 99, net: 1101, capital: 6954 },
  { month: "Jul", income: 1500, expenses: 50, net: 1450, capital: 8404 },
  { month: "Ago", income: 1800, expenses: 99, net: 1701, capital: 10105 },
];

const phaseData = [
  { name: "En Curso", value: 1, color: COLORS.blue },
  { name: "Pendiente", value: 1, color: COLORS.textDim },
  { name: "Pasado", value: 0, color: COLORS.accent },
  { name: "Fallido", value: 0, color: COLORS.danger },
];

function KPICard({ label, value, subtitle, icon, color = COLORS.accent, trend }) {
  return (
    <div style={{
      background: COLORS.card,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 12,
      padding: "20px 24px",
      position: "relative",
      overflow: "hidden",
      transition: "all 0.3s ease",
    }}>
      <div style={{
        position: "absolute", top: 0, left: 0, right: 0, height: 3,
        background: `linear-gradient(90deg, ${color}, transparent)`,
      }} />
      <div style={{ fontSize: 13, color: COLORS.textDim, marginBottom: 8, letterSpacing: "0.05em", textTransform: "uppercase", fontFamily: "'JetBrains Mono', monospace" }}>
        {icon} {label}
      </div>
      <div style={{ fontSize: 28, fontWeight: 700, color: COLORS.text, fontFamily: "'JetBrains Mono', monospace" }}>
        {value}
      </div>
      {subtitle && (
        <div style={{ fontSize: 12, color: trend === "up" ? COLORS.profit : trend === "down" ? COLORS.danger : COLORS.textDim, marginTop: 4 }}>
          {subtitle}
        </div>
      )}
    </div>
  );
}

function EACard({ ea }) {
  const statusColor = ea.status === "Producción" ? COLORS.accent : ea.status === "Testing" ? COLORS.warning : COLORS.blue;
  return (
    <div style={{
      background: COLORS.card, border: `1px solid ${COLORS.border}`,
      borderRadius: 12, padding: 20, marginBottom: 12,
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
        <div>
          <div style={{ fontSize: 16, fontWeight: 700, color: COLORS.text, fontFamily: "'JetBrains Mono', monospace" }}>{ea.name}</div>
          <div style={{ fontSize: 12, color: COLORS.textDim }}>{ea.instrument} · M5 · NY Session</div>
        </div>
        <span style={{
          padding: "4px 12px", borderRadius: 20, fontSize: 11, fontWeight: 600,
          background: `${statusColor}22`, color: statusColor, border: `1px solid ${statusColor}44`,
        }}>{ea.status}</span>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }}>
        {[
          { label: "Profit Factor", val: ea.pf.toFixed(2), good: ea.pf > 1.5 },
          { label: "Win Rate", val: `${ea.winRate}%`, good: ea.winRate > 55 },
          { label: "Max DD", val: `${ea.maxDD}%`, good: ea.maxDD < 5 },
          { label: "Sharpe", val: ea.sharpe.toFixed(1), good: ea.sharpe > 1.0 },
        ].map((m, i) => (
          <div key={i} style={{ textAlign: "center" }}>
            <div style={{ fontSize: 11, color: COLORS.textDim, marginBottom: 4 }}>{m.label}</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: m.good ? COLORS.accent : COLORS.warning, fontFamily: "'JetBrains Mono', monospace" }}>
              {m.val}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function ChallengeRow({ ch }) {
  const resultColors = {
    "En Curso": COLORS.blue, "Pasado": COLORS.accent,
    "Fallido": COLORS.danger, "Pendiente": COLORS.textDim,
  };
  return (
    <tr style={{ borderBottom: `1px solid ${COLORS.border}` }}>
      <td style={{ padding: "12px 8px", color: COLORS.textDim, fontSize: 13 }}>{ch.date || "—"}</td>
      <td style={{ padding: "12px 8px", color: COLORS.text, fontSize: 13, fontWeight: 600 }}>{ch.firm}</td>
      <td style={{ padding: "12px 8px", color: COLORS.text, fontSize: 13, fontFamily: "'JetBrains Mono', monospace" }}>${ch.size.toLocaleString()}</td>
      <td style={{ padding: "12px 8px", color: COLORS.gold, fontSize: 13, fontFamily: "'JetBrains Mono', monospace" }}>{ch.ea}</td>
      <td style={{ padding: "12px 8px", color: COLORS.textDim, fontSize: 13 }}>{ch.phase}</td>
      <td style={{ padding: "12px 8px" }}>
        <span style={{
          padding: "3px 10px", borderRadius: 12, fontSize: 11, fontWeight: 600,
          background: `${resultColors[ch.result] || COLORS.textDim}22`,
          color: resultColors[ch.result] || COLORS.textDim,
        }}>{ch.result}</span>
      </td>
      <td style={{ padding: "12px 8px", color: COLORS.text, fontSize: 13, fontFamily: "'JetBrains Mono', monospace" }}>${ch.cost}</td>
    </tr>
  );
}

export default function TradingDashboard() {
  const [activeTab, setActiveTab] = useState("overview");
  const [challenges] = useState(initialChallenges);
  const [eas] = useState(initialEAs);

  const totalSpent = challenges.reduce((s, c) => s + c.cost, 0);
  const totalChallenges = challenges.length;
  const passed = challenges.filter(c => c.result === "Pasado").length;

  const tabs = [
    { id: "overview", label: "Overview", icon: "◎" },
    { id: "challenges", label: "Challenges", icon: "⚡" },
    { id: "eas", label: "EAs", icon: "⚙" },
    { id: "financials", label: "Financials", icon: "$" },
  ];

  const customTooltip = ({ active, payload, label }) => {
    if (!active || !payload?.length) return null;
    return (
      <div style={{ background: "#1a2332", border: `1px solid ${COLORS.border}`, borderRadius: 8, padding: "10px 14px" }}>
        <div style={{ color: COLORS.textDim, fontSize: 12, marginBottom: 4 }}>{label}</div>
        {payload.map((p, i) => (
          <div key={i} style={{ color: p.color, fontSize: 13, fontWeight: 600, fontFamily: "'JetBrains Mono', monospace" }}>
            {p.name}: ${p.value.toLocaleString()}
          </div>
        ))}
      </div>
    );
  };

  return (
    <div style={{
      background: COLORS.bg, minHeight: "100vh", color: COLORS.text,
      fontFamily: "'Inter', -apple-system, sans-serif",
    }}>
      <link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;600;700&family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet" />

      {/* Header */}
      <div style={{
        background: "linear-gradient(135deg, #0a0e17 0%, #111827 50%, #0a0e17 100%)",
        borderBottom: `1px solid ${COLORS.border}`, padding: "20px 32px",
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ fontSize: 10, color: COLORS.accent, letterSpacing: "0.2em", textTransform: "uppercase", marginBottom: 4, fontFamily: "'JetBrains Mono', monospace" }}>
              Trading Business HQ
            </div>
            <div style={{ fontSize: 24, fontWeight: 700, background: `linear-gradient(135deg, ${COLORS.text}, ${COLORS.accent})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>
              Jose's Trading Co.
            </div>
          </div>
          <div style={{ fontSize: 12, color: COLORS.textDim, fontFamily: "'JetBrains Mono', monospace", textAlign: "right" }}>
            <div>Capital: <span style={{ color: COLORS.accent, fontWeight: 700 }}>&lt; $5,000</span></div>
            <div>EAs Activos: <span style={{ color: COLORS.gold }}>{eas.length}</span></div>
          </div>
        </div>

        {/* Tabs */}
        <div style={{ display: "flex", gap: 4, marginTop: 20 }}>
          {tabs.map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id)} style={{
              padding: "8px 20px", borderRadius: 8, border: "none", cursor: "pointer",
              fontSize: 13, fontWeight: 600, transition: "all 0.2s",
              background: activeTab === tab.id ? COLORS.accent : "transparent",
              color: activeTab === tab.id ? COLORS.bg : COLORS.textDim,
            }}>
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* Content */}
      <div style={{ padding: "24px 32px", maxWidth: 1200, margin: "0 auto" }}>

        {/* OVERVIEW TAB */}
        {activeTab === "overview" && (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 16, marginBottom: 24 }}>
              <KPICard icon="💰" label="Capital Disponible" value="< $5,000" subtitle="Capital inicial" color={COLORS.accent} />
              <KPICard icon="⚡" label="Challenges Activos" value={totalChallenges} subtitle={`$${totalSpent} invertido`} color={COLORS.blue} />
              <KPICard icon="🏆" label="Cuentas Funded" value={passed} subtitle="Meta: 4-6 cuentas" color={COLORS.gold} />
              <KPICard icon="📊" label="EAs en Arsenal" value={eas.length} subtitle="US30 + XAUUSD" color={COLORS.purple} />
            </div>

            {/* Projection Chart */}
            <div style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 24, marginBottom: 24 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 4 }}>Proyección de Capital (6 meses)</div>
              <div style={{ fontSize: 12, color: COLORS.textDim, marginBottom: 20 }}>Escenario conservador basado en plan de prop firms</div>
              <ResponsiveContainer width="100%" height={280}>
                <AreaChart data={monthlyData}>
                  <defs>
                    <linearGradient id="capitalGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor={COLORS.accent} stopOpacity={0.3} />
                      <stop offset="95%" stopColor={COLORS.accent} stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke={COLORS.border} />
                  <XAxis dataKey="month" stroke={COLORS.textDim} fontSize={12} />
                  <YAxis stroke={COLORS.textDim} fontSize={12} tickFormatter={v => `$${(v/1000).toFixed(1)}k`} />
                  <Tooltip content={customTooltip} />
                  <Area type="monotone" dataKey="capital" stroke={COLORS.accent} fill="url(#capitalGrad)" strokeWidth={2} name="Capital" />
                </AreaChart>
              </ResponsiveContainer>
            </div>

            {/* Phase Roadmap */}
            <div style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 24 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 16 }}>Roadmap del Negocio</div>
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: 16 }}>
                {[
                  { phase: "Fase 1", title: "Validación", time: "Sem 1-4", desc: "Primer challenge, un EA, una firma", status: "active", color: COLORS.accent },
                  { phase: "Fase 2", title: "Replicación", time: "Mes 2-3", desc: "2 challenges simultáneos, 2 EAs", status: "upcoming", color: COLORS.blue },
                  { phase: "Fase 3", title: "Multi-Firma", time: "Mes 4-6", desc: "Expandir a FTMO, MyFundedFX", status: "upcoming", color: COLORS.purple },
                  { phase: "Fase 4", title: "Escalar", time: "Mes 6+", desc: "4-6 cuentas funded, LLC", status: "future", color: COLORS.gold },
                ].map((p, i) => (
                  <div key={i} style={{
                    padding: 16, borderRadius: 10, border: `1px solid ${p.status === "active" ? p.color : COLORS.border}`,
                    background: p.status === "active" ? `${p.color}11` : "transparent",
                    opacity: p.status === "future" ? 0.5 : 1,
                  }}>
                    <div style={{ fontSize: 10, color: p.color, fontWeight: 700, letterSpacing: "0.1em", fontFamily: "'JetBrains Mono', monospace" }}>
                      {p.phase} · {p.time}
                      {p.status === "active" && " ← AQUÍ"}
                    </div>
                    <div style={{ fontSize: 15, fontWeight: 700, marginTop: 6 }}>{p.title}</div>
                    <div style={{ fontSize: 12, color: COLORS.textDim, marginTop: 4 }}>{p.desc}</div>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}

        {/* CHALLENGES TAB */}
        {activeTab === "challenges" && (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 16, marginBottom: 24 }}>
              <KPICard icon="🎯" label="Total Challenges" value={totalChallenges} color={COLORS.blue} />
              <KPICard icon="✅" label="Pasados" value={passed} color={COLORS.accent} />
              <KPICard icon="💸" label="Invertido" value={`$${totalSpent}`} color={COLORS.warning} />
              <KPICard icon="📈" label="Challenge Win Rate" value={totalChallenges > 0 ? `${((passed/totalChallenges)*100).toFixed(0)}%` : "N/A"} color={COLORS.purple} />
            </div>

            <div style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 24 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 16 }}>Challenge Tracker</div>
              <div style={{ overflowX: "auto" }}>
                <table style={{ width: "100%", borderCollapse: "collapse" }}>
                  <thead>
                    <tr style={{ borderBottom: `2px solid ${COLORS.border}` }}>
                      {["Fecha", "Prop Firm", "Cuenta", "EA", "Phase", "Estado", "Costo"].map(h => (
                        <th key={h} style={{ padding: "10px 8px", textAlign: "left", fontSize: 11, color: COLORS.textDim, textTransform: "uppercase", letterSpacing: "0.05em" }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {challenges.map(ch => <ChallengeRow key={ch.id} ch={ch} />)}
                  </tbody>
                </table>
              </div>
              <div style={{ marginTop: 16, padding: 12, background: `${COLORS.blue}11`, borderRadius: 8, fontSize: 12, color: COLORS.textDim }}>
                💡 <strong>Regla:</strong> Máximo 20% del capital en challenges activos. Con $5K → máximo $1,000 en challenges simultáneos.
              </div>
            </div>
          </>
        )}

        {/* EAs TAB */}
        {activeTab === "eas" && (
          <>
            <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 16 }}>Expert Advisors — Arsenal</div>
            {eas.map((ea, i) => <EACard key={i} ea={ea} />)}

            <div style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 24, marginTop: 16 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 16 }}>Comparación de EAs</div>
              <ResponsiveContainer width="100%" height={250}>
                <BarChart data={eas} layout="vertical" margin={{ left: 120 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke={COLORS.border} />
                  <XAxis type="number" stroke={COLORS.textDim} fontSize={12} />
                  <YAxis dataKey="name" type="category" stroke={COLORS.textDim} fontSize={12} />
                  <Tooltip content={customTooltip} />
                  <Bar dataKey="pf" name="Profit Factor" fill={COLORS.accent} radius={[0, 4, 4, 0]} barSize={20} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div style={{ marginTop: 16, padding: 16, background: `${COLORS.gold}11`, border: `1px solid ${COLORS.gold}33`, borderRadius: 10, fontSize: 13 }}>
              <strong style={{ color: COLORS.gold }}>⚙ Métricas objetivo para challenge:</strong>
              <div style={{ color: COLORS.textDim, marginTop: 6, lineHeight: 1.8 }}>
                Profit Factor &gt; 1.5 · Win Rate &gt; 55% · Max DD &lt; 5% · Sharpe &gt; 1.0
              </div>
            </div>
          </>
        )}

        {/* FINANCIALS TAB */}
        {activeTab === "financials" && (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: 16, marginBottom: 24 }}>
              <KPICard icon="🏦" label="Capital Inicial" value="< $5,000" color={COLORS.accent} />
              <KPICard icon="📤" label="Total Payouts" value="$0" subtitle="Aún sin funded accounts" color={COLORS.textDim} />
              <KPICard icon="📉" label="Total Gastos" value={`$${totalSpent}`} subtitle="Challenges" color={COLORS.danger} />
              <KPICard icon="📊" label="Net P&L" value={`-$${totalSpent}`} subtitle="Inversión en curso" color={COLORS.warning} />
            </div>

            <div style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 24, marginBottom: 24 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 4 }}>Income vs Expenses (Proyección)</div>
              <div style={{ fontSize: 12, color: COLORS.textDim, marginBottom: 20 }}>Basado en plan conservador de prop firm scaling</div>
              <ResponsiveContainer width="100%" height={280}>
                <BarChart data={monthlyData}>
                  <CartesianGrid strokeDasharray="3 3" stroke={COLORS.border} />
                  <XAxis dataKey="month" stroke={COLORS.textDim} fontSize={12} />
                  <YAxis stroke={COLORS.textDim} fontSize={12} tickFormatter={v => `$${v}`} />
                  <Tooltip content={customTooltip} />
                  <Bar dataKey="income" name="Ingresos" fill={COLORS.accent} radius={[4, 4, 0, 0]} />
                  <Bar dataKey="expenses" name="Gastos" fill={COLORS.danger} radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 24 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 12 }}>Reglas Financieras del Negocio</div>
              <div style={{ display: "grid", gap: 10 }}>
                {[
                  { rule: "Max 20% del capital en challenges", icon: "🛡️" },
                  { rule: "Reinvertir 50% de payouts en más challenges", icon: "🔄" },
                  { rule: "Reservar 30% para impuestos y LLC futura", icon: "🏛️" },
                  { rule: "20% es ganancia personal", icon: "💰" },
                  { rule: "3 fallos seguidos = pausar y re-evaluar", icon: "🚨" },
                ].map((r, i) => (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 14px", background: `${COLORS.border}55`, borderRadius: 8 }}>
                    <span style={{ fontSize: 18 }}>{r.icon}</span>
                    <span style={{ fontSize: 13, color: COLORS.text }}>{r.rule}</span>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}
      </div>

      {/* Footer */}
      <div style={{ textAlign: "center", padding: "24px 0", color: COLORS.textDim, fontSize: 11, fontFamily: "'JetBrains Mono', monospace" }}>
        Jose's Trading Co. · Dashboard v1.0 · Datos de ejemplo — actualiza con tus métricas reales
      </div>
    </div>
  );
}

