  { name: "Scalper_XAUUSD_v5", instrument: "XAUUSD", pf: 1.62, winRate: 58, maxDD: 5.1, trades: 289, sharpe: 1.1, status: "Testing" },
];

const monthlyData = [
  { month: "Mar", income: 0, expenses: 198, net: -198, capital: 4802 },
  { month: "Abr", income: 400, expenses: 50, net: 350, capital: 5152 },
  { month: "May", income: 800, expenses: 99, net: 701, capital: 5853 },
  { month: "Jun", income: 1200, expenses: 99, net: 1101, capital: 6954 },
  { month: "Jul", income: 1500, expenses: 50, net: 1450, capital: 8404 },
  { month: "Ago", income: 1800, expenses: 99, net: 1701, capital: 10105 },
];

const phaseData = [
  { name: "En Curso", value: 1, color: COLORS.blue },
  { name: "Pendiente", value: 1, color: COLORS.textDim },
  { name: "Pasado", value: 0, color: COLORS.accent },
  { name: "Fallido", value: 0, color: COLORS.danger },
];

function KPICard({ label, value, subtitle, icon, color = COLORS.accent, trend }) {
  return (
    <div style={{
      background: COLORS.card,
      border: `1px solid ${COLORS.border}`,
      borderRadius: 12,
      padding: "20px 24px",
      position: "relative",
      overflow: "hidden",
      transition: "all 0.3s ease",
    }}>
      <div style={{
        position: "absolute", top: 0, left: 0, right: 0, height: 3,
        background: `linear-gradient(90deg, ${color}, transparent)`,
      }} />
      <div style={{ fontSize: 13, color: COLORS.textDim, marginBottom: 8, letterSpacing: "0.05em", textTransform: "uppercase", fontFamily: "'JetBrains Mono', monospace" }}>
        {icon} {label}
      </div>
      <div style={{ fontSize: 28, fontWeight: 700, color: COLORS.text, fontFamily: "'JetBrains Mono', monospace" }}>
        {value}
      </div>
      {subtitle && (
        <div style={{ fontSize: 12, color: trend === "up" ? COLORS.profit : trend === "down" ? COLORS.danger : COLORS.textDim, marginTop: 4 }}>
          {subtitle}
        </div>
      )}
    </div>
  );
}

function EACard({ ea }) {
  const statusColor = ea.status === "Producción" ? COLORS.accent : ea.status === "Testing" ? COLORS.warning : COLORS.blue;
  return (
    <div style={{
      background: COLORS.card, border: `1px solid ${COLORS.border}`,
      borderRadius: 12, padding: 20, marginBottom: 12,
    }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
        <div>
          <div style={{ fontSize: 16, fontWeight: 700, color: COLORS.text, fontFamily: "'JetBrains Mono', monospace" }}>{ea.name}</div>
          <div style={{ fontSize: 12, color: COLORS.textDim }}>{ea.instrument} · M5 · NY Session</div>
        </div>
        <span style={{
          padding: "4px 12px", borderRadius: 20, fontSize: 11, fontWeight: 600,
          background: `${statusColor}22`, color: statusColor, border: `1px solid ${statusColor}44`,
        }}>{ea.status}</span>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12 }}>
        {[
          { label: "Profit Factor", val: ea.pf.toFixed(2), good: ea.pf > 1.5 },
          { label: "Win Rate", val: `${ea.winRate}%`, good: ea.winRate > 55 },
          { label: "Max DD", val: `${ea.maxDD}%`, good: ea.maxDD < 5 },
          { label: "Sharpe", val: ea.sharpe.toFixed(1), good: ea.sharpe > 1.0 },
        ].map((m, i) => (
          <div key={i} style={{ textAlign: "center" }}>
            <div style={{ fontSize: 11, color: COLORS.textDim, marginBottom: 4 }}>{m.label}</div>
            <div style={{ fontSize: 18, fontWeight: 700, color: m.good ? COLORS.accent : COLORS.warning, fontFamily: "'JetBrains Mono', monospace" }}>
              {m.val}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function ChallengeRow({ ch }) {
  const resultColors = {
    "En Curso": COLORS.blue, "Pasado": COLORS.accent,
    "Fallido": COLORS.danger, "Pendiente": COLORS.textDim,
  };
  return (
    <tr style={{ borderBottom: `1px solid ${COLORS.border}` }}>
      <td style={{ padding: "12px 8px", color: COLORS.textDim, fontSize: 13 }}>{ch.date || "—"}</td>
      <td style={{ padding: "12px 8px", color: COLORS.text, fontSize: 13, fontWeight: 600 }}>{ch.firm}</td>
      <td style={{ padding: "12px 8px", color: COLORS.text, fontSize: 13, fontFamily: "'JetBrains Mono', monospace" }}>${ch.size.toLocaleString()}</td>
      <td style={{ padding: "12px 8px", color: COLORS.gold, fontSize: 13, fontFamily: "'JetBrains Mono', monospace" }}>{ch.ea}</td>
      <td style={{ padding: "12px 8px", color: COLORS.textDim, fontSize: 13 }}>{ch.phase}</td>
      <td style={{ padding: "12px 8px" }}>
        <span style={{
          padding: "3px 10px", borderRadius: 12, fontSize: 11, fontWeight: 600,
          background: `${resultColors[ch.result] || COLORS.textDim}22`,
          color: resultColors[ch.result] || COLORS.textDim,
        }}>{ch.result}</span>
      </td>
      <td style={{ padding: "12px 8px", color: COLORS.text, fontSize: 13, fontFamily: "'JetBrains Mono', monospace" }}>${ch.cost}</td>
    </tr>
  );
}

export default function TradingDashboard() {
  const [activeTab, setActiveTab] = useState("overview");
