                  <Tooltip content={customTooltip} />
                  <Bar dataKey="income" name="Ingresos" fill={COLORS.accent} radius={[4, 4, 0, 0]} />
                  <Bar dataKey="expenses" name="Gastos" fill={COLORS.danger} radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div style={{ background: COLORS.card, border: `1px solid ${COLORS.border}`, borderRadius: 12, padding: 24 }}>
              <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 12 }}>Reglas Financieras del Negocio</div>
              <div style={{ display: "grid", gap: 10 }}>
                {[
                  { rule: "Max 20% del capital en challenges", icon: "🛡️" },
                  { rule: "Reinvertir 50% de payouts en más challenges", icon: "🔄" },
                  { rule: "Reservar 30% para impuestos y LLC futura", icon: "🏛️" },
                  { rule: "20% es ganancia personal", icon: "💰" },
                  { rule: "3 fallos seguidos = pausar y re-evaluar", icon: "🚨" },
                ].map((r, i) => (
                  <div key={i} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 14px", background: `${COLORS.border}55`, borderRadius: 8 }}>
                    <span style={{ fontSize: 18 }}>{r.icon}</span>
                    <span style={{ fontSize: 13, color: COLORS.text }}>{r.rule}</span>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}
      </div>

      {/* Footer */}
      <div style={{ textAlign: "center", padding: "24px 0", color: COLORS.textDim, fontSize: 11, fontFamily: "'JetBrains Mono', monospace" }}>
        Jose's Trading Co. · Dashboard v1.0 · Datos de ejemplo — actualiza con tus métricas reales
      </div>
    </div>
  );
}
