};

const PRESETS = [
  {
    icon: "📊",
    label: "Opening Range Breakout",
    prompt: "Create an Opening Range Breakout EA for US30 on M5. The opening range is defined as the high and low of the first 30 minutes of NY session (9:30-10:00 ET). Enter long on breakout above range high, short on breakout below range low. Stop loss at opposite side of the range. Take profit at 1.5x the range size. Max 1 trade per day. Include session filter and spread filter.",
  },
  {
    icon: "⚡",
    label: "Order Block Scalper",
    prompt: "Create a scalper EA for XAUUSD M5 that identifies Order Blocks (OBs). An OB is the last opposite candle before a strong move that breaks structure. Detect bullish OB: last bearish candle before a strong bullish move. Detect bearish OB: last bullish candle before a strong bearish move. Enter when price returns to the OB zone. SL below/above the OB. TP at 1:2 RR. NY session only. Max 2 trades per day.",
  },
  {
    icon: "🔲",
    label: "Fair Value Gap (FVG)",
    prompt: "Create an EA for US30 M5 that detects and trades Fair Value Gaps. A bullish FVG exists when candle[3].high < candle[1].low (gap between wick of candle 3 bars ago and wick of 1 bar ago). Enter long when price retraces into the FVG zone. SL below the FVG low. TP at previous swing high. Include BOS (Break of Structure) confirmation before taking the FVG entry. NY session filter.",
  },
  {
    icon: "📈",
    label: "VWAP Bounce",
    prompt: "Create an EA for XAUUSD M5 that calculates session VWAP (Volume Weighted Average Price) starting from NY session open. Enter long when price touches VWAP from above and bounces (bullish rejection candle). Enter short when price touches VWAP from below and rejects. SL 15 points from entry. TP at 1:2 risk-reward. Max spread 30 points. Include daily P&L check.",
  },
  {
    icon: "🛡️",
    label: "Prop Firm Guardian",
    prompt: "Create a utility EA/script that monitors prop firm rules in real-time. Track: daily P&L vs 5% daily drawdown limit, total equity vs 10% max drawdown from initial balance. If daily loss reaches 4% (warning) or 4.5% (critical), close all positions and disable trading for the day. Show an on-chart dashboard panel with: current P&L, remaining daily DD allowance, total DD status, number of trades today. Use Comment() or graphical objects for the display.",
  },
  {
    icon: "🔧",
    label: "Lot Size Calculator",
    prompt: "Create a reusable include file (.mqh) with a CLotCalculator class that handles proper lot sizing for CFD instruments. Methods: CalculateByRisk(double riskPercent, double slPoints) — risk-based sizing. CalculateByFixedAmount(double riskDollars, double slPoints) — fixed dollar risk. ValidateLot(double lots) — clamp to VOLUME_MIN/MAX, round to VOLUME_STEP. GetMaxLotForDD(double maxDDPercent) — maximum lot that respects drawdown limit. Include static methods and proper error handling.",
  },
];

const CODE_TYPE_OPTIONS = [
  { value: "ea", label: "Expert Advisor (.mq5)", icon: "🤖" },
  { value: "indicator", label: "Indicator (.mq5)", icon: "📊" },
  { value: "script", label: "Script (.mq5)", icon: "📜" },
  { value: "include", label: "Include File (.mqh)", icon: "📦" },
];

function CodeBlock({ code }) {
  const [copied, setCopied] = useState(false);
  const codeRef = useRef(null);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(code);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      const ta = document.createElement("textarea");
      ta.value = code;
      document.body.appendChild(ta);
      ta.select();
      document.execCommand("copy");
      document.body.removeChild(ta);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div style={{ position: "relative", borderRadius: 10, overflow: "hidden", border: `1px solid ${COLORS.border}` }}>
      <div style={{
        display: "flex", justifyContent: "space-between", alignItems: "center",
        padding: "8px 16px", background: COLORS.card, borderBottom: `1px solid ${COLORS.border}`,
      }}>
        <span style={{ fontSize: 12, color: COLORS.textDim, fontFamily: "'JetBrains Mono', monospace" }}>
          MQL5 Output
        </span>
        <button onClick={handleCopy} style={{
          background: copied ? COLORS.accentDim : "transparent",
          border: `1px solid ${copied ? COLORS.accent : COLORS.border}`,
          color: copied ? COLORS.accent : COLORS.textDim,
          padding: "4px 12px", borderRadius: 6, cursor: "pointer", fontSize: 11,
          fontFamily: "'JetBrains Mono', monospace", transition: "all 0.2s",
        }}>
          {copied ? "✓ Copiado" : "Copiar código"}
        </button>
      </div>
      <pre ref={codeRef} style={{
        background: COLORS.codeBg, color: COLORS.codeText, padding: 20,
        margin: 0, overflow: "auto", fontSize: 13, lineHeight: 1.6,
        fontFamily: "'JetBrains Mono', monospace", maxHeight: 500,
        whiteSpace: "pre-wrap", wordBreak: "break-word",
      }}>
        {code}
      </pre>
    </div>
  );
}

function TerminalLoader({ messages }) {
  const [visibleLines, setVisibleLines] = useState(0);
  useEffect(() => {
    if (visibleLines < messages.length) {
      const t = setTimeout(() => setVisibleLines(v => v + 1), 600);
      return () => clearTimeout(t);
    }
  }, [visibleLines, messages.length]);

  return (
    <div style={{
      background: COLORS.codeBg, border: `1px solid ${COLORS.border}`,
      borderRadius: 10, padding: 20, fontFamily: "'JetBrains Mono', monospace",
    }}>
      {messages.slice(0, visibleLines).map((msg, i) => (
        <div key={i} style={{ fontSize: 13, color: COLORS.accent, marginBottom: 6, opacity: 0.8 }}>
          <span style={{ color: COLORS.textDim }}>$</span> {msg}
        </div>
      ))}
      {visibleLines <= messages.length && (
        <div style={{ fontSize: 13, color: COLORS.accent }}>
          <span style={{ color: COLORS.textDim }}>$</span>{" "}
          <span style={{ animation: "blink 1s infinite" }}>█</span>
        </div>
      )}
      <style>{`@keyframes blink { 0%,50% {opacity:1} 51%,100% {opacity:0} }`}</style>
    </div>
  );
}

export default function MQL5Agent() {
  const [prompt, setPrompt] = useState("");
  const [codeType, setCodeType] = useState("ea");
  const [instrument, setInstrument] = useState("US30");
  const [output, setOutput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [history, setHistory] = useState([]);
  const [showHistory, setShowHistory] = useState(false);
  const textareaRef = useRef(null);

  const loaderMessages = [
    "Initializing MQL5 compiler context...",
    `Loading ${instrument} symbol specifications...`,
    "Applying prop firm risk constraints...",
    "Generating production-grade code...",
    "Validating lot sizing logic...",
    "Checking for look-ahead bias...",
  ];

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    setError("");
    setOutput("");

    const typeLabel = CODE_TYPE_OPTIONS.find(o => o.value === codeType)?.label || "Expert Advisor";
    const fullPrompt = `Generate a ${typeLabel} for ${instrument}.

User Request:
${prompt.trim()}

Remember: Follow all MQL5 coding standards from your instructions. Return ONLY the code, no explanations before or after.`;

    try {
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 8000,
          system: MQL5_SYSTEM_PROMPT,
          messages: [{ role: "user", content: fullPrompt }],
        }),
      });

      if (!response.ok) {
        const errData = await response.json().catch(() => ({}));
        throw new Error(errData?.error?.message || `API error: ${response.status}`);
      }

      const data = await response.json();
      const code = data.content
        .filter(b => b.type === "text")
        .map(b => b.text)
        .join("\n")
        .replace(/```mql5?\n?/g, "")
        .replace(/```\n?/g, "")
        .trim();

      setOutput(code);
      setHistory(prev => [{
        timestamp: new Date().toLocaleString(),
        prompt: prompt.trim().slice(0, 80) + (prompt.length > 80 ? "..." : ""),
        instrument,
        codeType,
        code,
      }, ...prev].slice(0, 20));
    } catch (err) {
      setError(err.message || "Error generating code. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handlePreset = (preset) => {
    setPrompt(preset.prompt);
    if (preset.prompt.toLowerCase().includes("xauusd")) setInstrument("XAUUSD");
    else if (preset.prompt.toLowerCase().includes("us30")) setInstrument("US30");
    if (preset.prompt.toLowerCase().includes("include file")) setCodeType("include");
    else if (preset.prompt.toLowerCase().includes("script")) setCodeType("script");
    else if (preset.prompt.toLowerCase().includes("indicator")) setCodeType("indicator");
    else setCodeType("ea");
    textareaRef.current?.focus();
  };

  return (
    <div style={{ background: COLORS.bg, minHeight: "100vh", color: COLORS.text, fontFamily: "'Inter', -apple-system, sans-serif" }}>
      <link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet" />

      {/* Header */}
      <div style={{
        background: `linear-gradient(180deg, ${COLORS.surface} 0%, ${COLORS.bg} 100%)`,
        borderBottom: `1px solid ${COLORS.border}`, padding: "20px 28px",
      }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
          <div>
            <div style={{
              fontSize: 11, color: COLORS.accent, letterSpacing: "0.25em",
              textTransform: "uppercase", marginBottom: 6,
              fontFamily: "'JetBrains Mono', monospace",
            }}>
              Agent #3 · MQL5 Code Generator
            </div>
            <div style={{ fontSize: 22, fontWeight: 700 }}>
              <span style={{ color: COLORS.accent }}>&gt;_</span> MQL5 Forge
            </div>
            <div style={{ fontSize: 12, color: COLORS.textDim, marginTop: 4 }}>
              Describe tu estrategia en español o inglés → código MQL5 listo para compilar
            </div>
          </div>
          <button
            onClick={() => setShowHistory(!showHistory)}
            style={{
              background: showHistory ? COLORS.accentDim : "transparent",
              border: `1px solid ${showHistory ? COLORS.accent : COLORS.border}`,
              color: showHistory ? COLORS.accent : COLORS.textDim,
              padding: "6px 14px", borderRadius: 8, cursor: "pointer", fontSize: 12,
              fontFamily: "'JetBrains Mono', monospace",
            }}
          >
            Historial ({history.length})
          </button>
        </div>
      </div>

      <div style={{ maxWidth: 900, margin: "0 auto", padding: "24px 28px" }}>

        {/* History Panel */}
        {showHistory && history.length > 0 && (
          <div style={{
            background: COLORS.card, border: `1px solid ${COLORS.border}`,
            borderRadius: 12, padding: 16, marginBottom: 20,
          }}>
            <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 12, color: COLORS.textDim }}>Generaciones recientes</div>
            {history.map((h, i) => (
              <div
                key={i}
                onClick={() => { setOutput(h.code); setShowHistory(false); }}
                style={{
                  padding: "10px 12px", borderRadius: 8, marginBottom: 4,
                  cursor: "pointer", transition: "background 0.2s",
                  background: "transparent", display: "flex", justifyContent: "space-between",
                  alignItems: "center", fontSize: 12,
                }}
                onMouseEnter={e => e.currentTarget.style.background = COLORS.surface}
                onMouseLeave={e => e.currentTarget.style.background = "transparent"}
              >
                <div>
                  <span style={{ color: COLORS.accent, fontFamily: "'JetBrains Mono', monospace" }}>{h.instrument}</span>
                  <span style={{ color: COLORS.textMuted, margin: "0 8px" }}>·</span>
                  <span style={{ color: COLORS.text }}>{h.prompt}</span>
                </div>
                <span style={{ color: COLORS.textMuted, fontSize: 11, whiteSpace: "nowrap" }}>{h.timestamp}</span>
              </div>
            ))}
          </div>
        )}

        {/* Quick Templates */}
        <div style={{ marginBottom: 20 }}>
          <div style={{ fontSize: 11, color: COLORS.textDim, marginBottom: 10, letterSpacing: "0.1em", textTransform: "uppercase", fontFamily: "'JetBrains Mono', monospace" }}>
            Quick Templates
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(170px, 1fr))", gap: 8 }}>
            {PRESETS.map((p, i) => (
              <button
                key={i}
                onClick={() => handlePreset(p)}
                style={{
                  background: COLORS.card, border: `1px solid ${COLORS.border}`,
                  borderRadius: 10, padding: "12px 14px", cursor: "pointer",
                  textAlign: "left", transition: "all 0.2s", color: COLORS.text,
                }}
                onMouseEnter={e => { e.currentTarget.style.borderColor = COLORS.accent; e.currentTarget.style.background = COLORS.surface; }}
                onMouseLeave={e => { e.currentTarget.style.borderColor = COLORS.border; e.currentTarget.style.background = COLORS.card; }}
              >
                <div style={{ fontSize: 18, marginBottom: 6 }}>{p.icon}</div>
                <div style={{ fontSize: 12, fontWeight: 600, lineHeight: 1.3 }}>{p.label}</div>
              </button>
            ))}
          </div>
        </div>

        {/* Config Row */}
        <div style={{ display: "flex", gap: 12, marginBottom: 12, flexWrap: "wrap" }}>
          <div style={{ flex: 1, minWidth: 180 }}>
            <div style={{ fontSize: 11, color: COLORS.textDim, marginBottom: 6, fontFamily: "'JetBrains Mono', monospace" }}>Tipo de archivo</div>
            <div style={{ display: "flex", gap: 4 }}>
              {CODE_TYPE_OPTIONS.map(opt => (
                <button
                  key={opt.value}
                  onClick={() => setCodeType(opt.value)}
                  style={{
                    flex: 1, padding: "8px 6px", borderRadius: 8, border: "1px solid",
                    borderColor: codeType === opt.value ? COLORS.accent : COLORS.border,
                    background: codeType === opt.value ? COLORS.accentDim : COLORS.card,
                    color: codeType === opt.value ? COLORS.accent : COLORS.textDim,
                    cursor: "pointer", fontSize: 11, fontWeight: 600, transition: "all 0.2s",
                  }}
                >
                  {opt.icon} {opt.value.toUpperCase()}
                </button>
              ))}
            </div>
          </div>
          <div style={{ minWidth: 140 }}>
            <div style={{ fontSize: 11, color: COLORS.textDim, marginBottom: 6, fontFamily: "'JetBrains Mono', monospace" }}>Instrumento</div>
            <div style={{ display: "flex", gap: 4 }}>
              {["US30", "XAUUSD", "NAS100", "Custom"].map(sym => (
                <button
                  key={sym}
                  onClick={() => setInstrument(sym)}
                  style={{
                    padding: "8px 12px", borderRadius: 8, border: "1px solid",
                    borderColor: instrument === sym ? COLORS.accent : COLORS.border,
                    background: instrument === sym ? COLORS.accentDim : COLORS.card,
                    color: instrument === sym ? COLORS.accent : COLORS.textDim,
                    cursor: "pointer", fontSize: 11, fontWeight: 600, transition: "all 0.2s",
                  }}
                >
                  {sym}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Prompt Input */}
        <div style={{
          background: COLORS.card, border: `1px solid ${COLORS.border}`,
          borderRadius: 12, overflow: "hidden", marginBottom: 20,
        }}>
          <div style={{
            padding: "10px 16px", borderBottom: `1px solid ${COLORS.border}`,
            display: "flex", alignItems: "center", gap: 8,
          }}>
            <span style={{ color: COLORS.accent, fontFamily: "'JetBrains Mono', monospace", fontSize: 13 }}>&gt;</span>
            <span style={{ fontSize: 12, color: COLORS.textDim }}>Describe tu estrategia o lo que necesitas</span>
          </div>
          <textarea
            ref={textareaRef}
            value={prompt}
            onChange={e => setPrompt(e.target.value)}
            placeholder={"Ej: Crea un EA que detecte Break of Structure en US30 M5 y entre en el retroceso al Order Block más cercano. SL debajo del OB, TP en 1:2 RR. Solo durante NY session. Max 1 trade por día. Incluir filtro de spread y daily loss limit para prop firm..."}
            style={{
              width: "100%", minHeight: 140, padding: "16px 20px",
              background: COLORS.inputBg, border: "none", color: COLORS.text,
              fontSize: 14, lineHeight: 1.6, resize: "vertical",
              fontFamily: "'Inter', sans-serif", outline: "none",
              boxSizing: "border-box",
            }}
          />
          <div style={{
            padding: "10px 16px", borderTop: `1px solid ${COLORS.border}`,
            display: "flex", justifyContent: "space-between", alignItems: "center",
          }}>
            <span style={{ fontSize: 11, color: COLORS.textMuted, fontFamily: "'JetBrains Mono', monospace" }}>
              {prompt.length} chars
            </span>
            <button
              onClick={handleGenerate}
              disabled={loading || !prompt.trim()}
              style={{
                background: loading ? COLORS.textMuted : `linear-gradient(135deg, ${COLORS.accent}, ${COLORS.accentMuted})`,
                border: "none", color: COLORS.bg, padding: "10px 28px",
                borderRadius: 8, cursor: loading ? "wait" : "pointer",
                fontSize: 13, fontWeight: 700, transition: "all 0.2s",
                fontFamily: "'JetBrains Mono', monospace",
                opacity: !prompt.trim() ? 0.4 : 1,
              }}
            >
              {loading ? "Generating..." : "⚡ Generar código"}
            </button>
          </div>
        </div>

        {/* Loading State */}
        {loading && <TerminalLoader messages={loaderMessages} />}

        {/* Error */}
        {error && (
          <div style={{
            background: `${COLORS.danger}11`, border: `1px solid ${COLORS.danger}44`,
            borderRadius: 10, padding: 16, marginBottom: 20,
          }}>
            <div style={{ fontSize: 13, color: COLORS.danger, fontWeight: 600, marginBottom: 4 }}>Error</div>
            <div style={{ fontSize: 12, color: COLORS.text }}>{error}</div>
          </div>
        )}

        {/* Output */}
        {output && !loading && (
          <div style={{ marginTop: 20 }}>
            <div style={{
              display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12,
            }}>
              <div style={{ fontSize: 11, color: COLORS.textDim, letterSpacing: "0.1em", textTransform: "uppercase", fontFamily: "'JetBrains Mono', monospace" }}>
                Generated Output · {instrument} · {codeType.toUpperCase()}
              </div>
              <div style={{ fontSize: 11, color: COLORS.textMuted, fontFamily: "'JetBrains Mono', monospace" }}>
                {output.split("\n").length} líneas
              </div>
            </div>
            <CodeBlock code={output} />

            <div style={{
              marginTop: 16, padding: 14, background: `${COLORS.accent}08`,
              border: `1px solid ${COLORS.accent}22`, borderRadius: 10,
              fontSize: 12, color: COLORS.textDim, lineHeight: 1.6,
            }}>
              <strong style={{ color: COLORS.accent }}>Próximos pasos:</strong> Copia el código → pégalo en MetaEditor → compila (F7) → prueba en Strategy Tester antes de usar en cuenta real o challenge. Si hay errores de compilación, pega el error aquí y te lo corrijo.
            </div>
          </div>
        )}

        {/* Empty State */}
        {!output && !loading && !error && (
          <div style={{
            textAlign: "center", padding: "48px 20px", color: COLORS.textMuted,
          }}>
            <div style={{ fontSize: 40, marginBottom: 16, opacity: 0.4 }}>⚡</div>
            <div style={{ fontSize: 14, color: COLORS.textDim, marginBottom: 8 }}>
              Describe tu estrategia o selecciona un template
            </div>
            <div style={{ fontSize: 12, color: COLORS.textMuted }}>
              El agente genera código MQL5 con tus estándares: lot sizing para CFDs, sin look-ahead bias, filtro NY session, reglas prop firm
            </div>
          </div>
        )}
      </div>

      {/* Footer */}
      <div style={{
        textAlign: "center", padding: "20px 0", fontSize: 11,
        color: COLORS.textMuted, fontFamily: "'JetBrains Mono', monospace",
      }}>
        MQL5 Forge · Agent #3 · Jose's Trading Co. · Powered by Claude API
      </div>
    </div>
  );
}

