          <div style={{
            textAlign: "center", padding: "48px 20px", color: COLORS.textMuted,
          }}>
            <div style={{ fontSize: 40, marginBottom: 16, opacity: 0.4 }}>⚡</div>
            <div style={{ fontSize: 14, color: COLORS.textDim, marginBottom: 8 }}>
              Describe tu estrategia o selecciona un template
            </div>
            <div style={{ fontSize: 12, color: COLORS.textMuted }}>
              El agente genera código MQL5 con tus estándares: lot sizing para CFDs, sin look-ahead bias, filtro NY session, reglas prop firm
            </div>
          </div>
        )}
      </div>

      {/* Footer */}
      <div style={{
        textAlign: "center", padding: "20px 0", fontSize: 11,
        color: COLORS.textMuted, fontFamily: "'JetBrains Mono', monospace",
      }}>
        MQL5 Forge · Agent #3 · Jose's Trading Co. · Powered by Claude API
      </div>
    </div>
  );
}
