  { id: 12, task: "Optimizar EAs basado en datos live", phase: 2, cat: "Tech", startMonth: 5, startWeek: 1, duration: 8, priority: "Alta", done: false, notes: "Comparar backtest vs live performance" },
  { id: 13, task: "Crear portafolio profesional (PDF)", phase: 2, cat: "Operativo", startMonth: 6, startWeek: 1, duration: 2, priority: "Media", done: false, notes: "Track record, métricas, estrategia" },
  { id: 14, task: "Establecer rutina de journaling de trades", phase: 2, cat: "Trading", startMonth: 5, startWeek: 1, duration: 2, priority: "Media", done: false, notes: "Post-sesión: qué pasó, por qué, lecciones" },

  // Phase 3
  { id: 15, task: "Investigar FTMO / MyFundedFX / reglas", phase: 3, cat: "Trading", startMonth: 7, startWeek: 1, duration: 2, priority: "Alta", done: false, notes: "Comparar reglas de DD, profit split, payout freq" },
  { id: 16, task: "Adaptar EAs a reglas de segunda prop firm", phase: 3, cat: "Tech", startMonth: 7, startWeek: 2, duration: 4, priority: "Alta", done: false, notes: "Ajustar parámetros de DD, lot sizing" },
  { id: 17, task: "Comprar challenge en segunda prop firm", phase: 3, cat: "Trading", startMonth: 7, startWeek: 4, duration: 1, priority: "Alta", done: false, notes: "No depender de una sola firma" },
  { id: 18, task: "Meta: 3-4 cuentas funded activas", phase: 3, cat: "Trading", startMonth: 8, startWeek: 1, duration: 8, priority: "Alta", done: false, notes: "Streams de ingreso paralelos" },
  { id: 19, task: "Contratar VPS dedicado para EAs", phase: 3, cat: "Tech", startMonth: 7, startWeek: 1, duration: 2, priority: "Media", done: false, notes: "Latencia baja, uptime 99.9%" },
  { id: 20, task: "Automatizar reporting mensual", phase: 3, cat: "Operativo", startMonth: 8, startWeek: 1, duration: 4, priority: "Baja", done: false, notes: "Script que genere P&L automático" },

  // Phase 4
  { id: 21, task: "Investigar LLC Wyoming — requisitos", phase: 4, cat: "Legal", startMonth: 10, startWeek: 1, duration: 2, priority: "Alta", done: false, notes: "EIN, ITIN, agente registrado" },
  { id: 22, task: "Consultar abogado (trader venezolano + LLC USA)", phase: 4, cat: "Legal", startMonth: 10, startWeek: 2, duration: 2, priority: "Alta", done: false, notes: "Implicaciones fiscales VE + OFAC" },
  { id: 23, task: "Registrar LLC", phase: 4, cat: "Legal", startMonth: 10, startWeek: 4, duration: 4, priority: "Alta", done: false, notes: "~$300-500 formación" },
  { id: 24, task: "Abrir cuenta bancaria empresarial (Mercury/Relay)", phase: 4, cat: "Financiero", startMonth: 11, startWeek: 2, duration: 4, priority: "Alta", done: false, notes: "Requiere EIN de la LLC" },
  { id: 25, task: "Migrar operaciones a estructura empresarial", phase: 4, cat: "Operativo", startMonth: 12, startWeek: 1, duration: 4, priority: "Media", done: false, notes: "Cuentas, facturación, contabilidad" },
  { id: 26, task: "Meta: $50K+ en capital funded combinado", phase: 4, cat: "Trading", startMonth: 12, startWeek: 1, duration: 4, priority: "Alta", done: false, notes: "4-6 cuentas funded operando" },
];

const C = {
  bg: "#08090d",
  surface: "#0f1117",
  card: "#151821",
  border: "#1e2330",
  borderLight: "#2a3040",
  accent: "#00d4aa",
  text: "#e2e8f0",
  textDim: "#64748b",
  textMuted: "#3a4255",
  done: "#00d4aa33",
};

export default function GanttTimeline() {
  const [tasks, setTasks] = useState(initialTasks);
  const [filterPhase, setFilterPhase] = useState(0);
  const [filterCat, setFilterCat] = useState("Todas");
  const [selectedTask, setSelectedTask] = useState(null);
  const [showAddTask, setShowAddTask] = useState(false);
  const [newTask, setNewTask] = useState({ task: "", phase: 1, cat: "Trading", startMonth: 3, startWeek: 1, duration: 2, priority: "Media", notes: "" });

  const toggleDone = (id) => {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, done: !t.done } : t));
  };

  const deleteTask = (id) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    setSelectedTask(null);
  };

  const addTask = () => {
    if (!newTask.task.trim()) return;
    const maxId = Math.max(...tasks.map(t => t.id), 0);
    setTasks(prev => [...prev, { ...newTask, id: maxId + 1, done: false }]);
    setNewTask({ task: "", phase: 1, cat: "Trading", startMonth: 3, startWeek: 1, duration: 2, priority: "Media", notes: "" });
    setShowAddTask(false);
  };

  const filtered = useMemo(() => {
    return tasks.filter(t => {
      if (filterPhase > 0 && t.phase !== filterPhase) return false;
      if (filterCat !== "Todas" && t.cat !== filterCat) return false;
      return true;
    });
  }, [tasks, filterPhase, filterCat]);

  const stats = useMemo(() => {
    const total = tasks.length;
    const done = tasks.filter(t => t.done).length;
    const alta = tasks.filter(t => t.priority === "Alta" && !t.done).length;
    return { total, done, pct: total ? Math.round((done / total) * 100) : 0, alta };
  }, [tasks]);

  const totalWeeks = MONTHS.length * 4;
  const getBarLeft = (t) => ((t.startMonth - 3) * 4 + (t.startWeek - 1)) / totalWeeks * 100;
  const getBarWidth = (t) => Math.max(t.duration / totalWeeks * 100, 1.5);

  const phaseForTask = (t) => PHASES.find(p => p.id === t.phase);

  return (
    <div style={{ background: C.bg, minHeight: "100vh", color: C.text, fontFamily: "'Inter', -apple-system, sans-serif" }}>
      <link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet" />

      {/* Header */}
      <div style={{ padding: "20px 24px", borderBottom: `1px solid ${C.border}`, background: C.surface }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 12 }}>
          <div>
            <div style={{ fontSize: 10, color: C.accent, letterSpacing: "0.25em", textTransform: "uppercase", fontFamily: "'JetBrains Mono', monospace", marginBottom: 4 }}>
              Jose's Trading Co. · Business Roadmap
            </div>
            <div style={{ fontSize: 20, fontWeight: 700 }}>
              Timeline & Objectives <span style={{ fontSize: 14, color: C.textDim, fontWeight: 400 }}>2026</span>
            </div>
          </div>
          <div style={{ display: "flex", gap: 12, alignItems: "center", flexWrap: "wrap" }}>
            {/* Progress */}
            <div style={{ textAlign: "right", minWidth: 100 }}>
              <div style={{ fontSize: 24, fontWeight: 700, fontFamily: "'JetBrains Mono', monospace", color: C.accent }}>{stats.pct}%</div>
              <div style={{ fontSize: 11, color: C.textDim }}>{stats.done}/{stats.total} tareas</div>
            </div>
            <div style={{ width: 1, height: 36, background: C.border }} />
            <div style={{ textAlign: "right" }}>
              <div style={{ fontSize: 18, fontWeight: 700, fontFamily: "'JetBrains Mono', monospace", color: "#f59e0b" }}>{stats.alta}</div>
              <div style={{ fontSize: 11, color: C.textDim }}>prioridad alta</div>
            </div>
          </div>
        </div>

        {/* Filters */}
        <div style={{ display: "flex", gap: 8, marginTop: 16, flexWrap: "wrap", alignItems: "center" }}>
          <span style={{ fontSize: 11, color: C.textDim, fontFamily: "'JetBrains Mono', monospace" }}>Fase:</span>
          {[{ id: 0, name: "Todas", color: C.textDim }, ...PHASES].map(p => (
            <button key={p.id} onClick={() => setFilterPhase(p.id)} style={{
              padding: "5px 14px", borderRadius: 20, fontSize: 11, fontWeight: 600, cursor: "pointer",
              border: `1px solid ${filterPhase === p.id ? p.color : C.border}`,
              background: filterPhase === p.id ? `${p.color}22` : "transparent",
              color: filterPhase === p.id ? p.color : C.textDim, transition: "all 0.2s",
            }}>{p.id > 0 ? `F${p.id}: ` : ""}{p.name}</button>
          ))}
          <div style={{ width: 1, height: 20, background: C.border, margin: "0 4px" }} />
          <span style={{ fontSize: 11, color: C.textDim, fontFamily: "'JetBrains Mono', monospace" }}>Cat:</span>
          {["Todas", ...Object.keys(CATEGORIES)].map(cat => (
            <button key={cat} onClick={() => setFilterCat(cat)} style={{
              padding: "5px 12px", borderRadius: 20, fontSize: 11, fontWeight: 600, cursor: "pointer",
              border: `1px solid ${filterCat === cat ? (CATEGORIES[cat] || C.textDim) : C.border}`,
              background: filterCat === cat ? `${CATEGORIES[cat] || C.textDim}22` : "transparent",
              color: filterCat === cat ? (CATEGORIES[cat] || C.textDim) : C.textDim, transition: "all 0.2s",
            }}>{cat}</button>
          ))}
          <div style={{ flex: 1 }} />
          <button onClick={() => setShowAddTask(!showAddTask)} style={{
            padding: "6px 16px", borderRadius: 8, fontSize: 12, fontWeight: 700, cursor: "pointer",
            background: showAddTask ? C.card : C.accent, border: "none",
            color: showAddTask ? C.accent : C.bg, transition: "all 0.2s",
          }}>{showAddTask ? "✕ Cerrar" : "+ Nueva tarea"}</button>
        </div>
      </div>

      {/* Add Task Panel */}
      {showAddTask && (
        <div style={{ padding: "16px 24px", background: C.card, borderBottom: `1px solid ${C.border}` }}>
          <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr 1fr 1fr 1fr auto", gap: 10, alignItems: "end" }}>
            <div>
              <div style={{ fontSize: 10, color: C.textDim, marginBottom: 4 }}>Tarea</div>
              <input value={newTask.task} onChange={e => setNewTask({ ...newTask, task: e.target.value })}
                placeholder="Nombre de la tarea..." style={{
                  width: "100%", padding: "8px 12px", borderRadius: 6, border: `1px solid ${C.border}`,
                  background: C.surface, color: C.text, fontSize: 13, outline: "none", boxSizing: "border-box",
                }} />
            </div>
            <div>
              <div style={{ fontSize: 10, color: C.textDim, marginBottom: 4 }}>Fase</div>
              <select value={newTask.phase} onChange={e => setNewTask({ ...newTask, phase: +e.target.value })} style={{
                width: "100%", padding: "8px", borderRadius: 6, border: `1px solid ${C.border}`,
                background: C.surface, color: C.text, fontSize: 12,
              }}>
                {PHASES.map(p => <option key={p.id} value={p.id}>F{p.id}: {p.name}</option>)}
              </select>
            </div>
            <div>
              <div style={{ fontSize: 10, color: C.textDim, marginBottom: 4 }}>Categoría</div>
              <select value={newTask.cat} onChange={e => setNewTask({ ...newTask, cat: e.target.value })} style={{
                width: "100%", padding: "8px", borderRadius: 6, border: `1px solid ${C.border}`,
                background: C.surface, color: C.text, fontSize: 12,
              }}>
                {Object.keys(CATEGORIES).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div>
              <div style={{ fontSize: 10, color: C.textDim, marginBottom: 4 }}>Mes inicio</div>
              <select value={newTask.startMonth} onChange={e => setNewTask({ ...newTask, startMonth: +e.target.value })} style={{
                width: "100%", padding: "8px", borderRadius: 6, border: `1px solid ${C.border}`,
                background: C.surface, color: C.text, fontSize: 12,
              }}>
                {MONTHS.map(m => <option key={m.key} value={m.key}>{m.label}</option>)}
              </select>
            </div>
            <div>
              <div style={{ fontSize: 10, color: C.textDim, marginBottom: 4 }}>Duración (sem)</div>
              <select value={newTask.duration} onChange={e => setNewTask({ ...newTask, duration: +e.target.value })} style={{
                width: "100%", padding: "8px", borderRadius: 6, border: `1px solid ${C.border}`,
                background: C.surface, color: C.text, fontSize: 12,
              }}>
                {[1, 2, 3, 4, 6, 8, 10, 12].map(d => <option key={d} value={d}>{d} sem</option>)}
              </select>
            </div>
            <button onClick={addTask} style={{
              padding: "8px 20px", borderRadius: 6, background: C.accent, border: "none",
              color: C.bg, fontWeight: 700, fontSize: 12, cursor: "pointer", whiteSpace: "nowrap",
            }}>Agregar</button>
          </div>
        </div>
      )}

      <div style={{ padding: "20px 24px", overflowX: "auto" }}>
        {/* Phase Headers on Timeline */}
        <div style={{ display: "flex", marginBottom: 4, minWidth: 900 }}>
          <div style={{ width: 280, flexShrink: 0 }} />
          <div style={{ flex: 1, position: "relative", height: 24 }}>
            {PHASES.map(phase => {
              const startIdx = phase.months[0] - 3;
              const span = phase.months.length;
              const left = (startIdx / MONTHS.length) * 100;
              const width = (span / MONTHS.length) * 100;
              return (
                <div key={phase.id} style={{
                  position: "absolute", left: `${left}%`, width: `${width}%`, height: "100%",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 10, fontWeight: 700, color: phase.color, letterSpacing: "0.1em",
                  textTransform: "uppercase", fontFamily: "'JetBrains Mono', monospace",
                  borderBottom: `2px solid ${phase.color}`,
                }}>
                  Fase {phase.id}: {phase.name}
                </div>
              );
            })}
          </div>
        </div>

        {/* Month Headers */}
        <div style={{ display: "flex", marginBottom: 8, minWidth: 900 }}>
          <div style={{ width: 280, flexShrink: 0, fontSize: 10, color: C.textDim, padding: "8px 0", fontFamily: "'JetBrains Mono', monospace" }}>
            TAREA
          </div>
          <div style={{ flex: 1, display: "flex" }}>
            {MONTHS.map(m => (
              <div key={m.key} style={{
                flex: 1, textAlign: "center", fontSize: 11, color: C.textDim, padding: "8px 0",
                borderLeft: `1px solid ${C.border}`, fontFamily: "'JetBrains Mono', monospace",
              }}>
                {m.label}
              </div>
            ))}
          </div>
        </div>

        {/* Task Rows */}
        <div style={{ minWidth: 900 }}>
          {filtered.map(t => {
            const phase = phaseForTask(t);
            const barLeft = getBarLeft(t);
            const barWidth = getBarWidth(t);
            const isSelected = selectedTask === t.id;
            return (
              <div key={t.id}>
                <div
                  onClick={() => setSelectedTask(isSelected ? null : t.id)}
                  style={{
                    display: "flex", alignItems: "center", padding: "6px 0",
                    borderBottom: `1px solid ${C.border}11`, cursor: "pointer",
                    transition: "background 0.15s",
                    background: isSelected ? `${C.accent}08` : "transparent",
                    opacity: t.done ? 0.5 : 1,
                  }}
                  onMouseEnter={e => { if (!isSelected) e.currentTarget.style.background = `${C.card}`; }}
                  onMouseLeave={e => { if (!isSelected) e.currentTarget.style.background = "transparent"; }}
                >
                  {/* Task name column */}
                  <div style={{ width: 280, flexShrink: 0, display: "flex", alignItems: "center", gap: 8, paddingRight: 12 }}>
                    <button onClick={(e) => { e.stopPropagation(); toggleDone(t.id); }} style={{
                      width: 18, height: 18, borderRadius: 4, border: `2px solid ${t.done ? C.accent : C.borderLight}`,
                      background: t.done ? C.accent : "transparent", cursor: "pointer",
                      display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0,
                      fontSize: 10, color: C.bg, fontWeight: 700, transition: "all 0.2s",
                    }}>{t.done ? "✓" : ""}</button>
                    <div style={{ minWidth: 0 }}>
                      <div style={{
                        fontSize: 12, fontWeight: 500, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                        textDecoration: t.done ? "line-through" : "none", color: t.done ? C.textDim : C.text,
                      }}>{t.task}</div>
                      <div style={{ display: "flex", gap: 6, marginTop: 2 }}>
                        <span style={{
                          fontSize: 9, padding: "1px 6px", borderRadius: 4,
                          background: `${CATEGORIES[t.cat]}22`, color: CATEGORIES[t.cat],
                        }}>{t.cat}</span>
                        {t.priority === "Alta" && (
                          <span style={{ fontSize: 9, padding: "1px 6px", borderRadius: 4, background: "#ef444422", color: "#ef4444" }}>Alta</span>
                        )}
                      </div>
                    </div>
                  </div>

                  {/* Gantt bar */}
                  <div style={{ flex: 1, position: "relative", height: 28 }}>
                    {/* Grid lines */}
                    {MONTHS.map((m, i) => (
                      <div key={i} style={{
                        position: "absolute", left: `${(i / MONTHS.length) * 100}%`,
                        top: 0, bottom: 0, width: 1, background: `${C.border}66`,
                      }} />
                    ))}
                    {/* Bar */}
                    <div style={{
                      position: "absolute", left: `${barLeft}%`, width: `${barWidth}%`,
                      top: 4, height: 20, borderRadius: 4,
                      background: t.done
                        ? `${phase?.color || C.accent}44`
                        : `linear-gradient(90deg, ${phase?.color || C.accent}cc, ${phase?.color || C.accent}88)`,
                      border: `1px solid ${phase?.color || C.accent}66`,
                      transition: "all 0.3s",
                      display: "flex", alignItems: "center", justifyContent: "center",
                      overflow: "hidden",
                    }}>
                      {barWidth > 4 && (
                        <span style={{ fontSize: 9, color: C.text, fontWeight: 600, whiteSpace: "nowrap", padding: "0 4px", fontFamily: "'JetBrains Mono', monospace" }}>
                          {t.duration}w
                        </span>
                      )}
                    </div>
                  </div>
                </div>

                {/* Expanded detail */}
                {isSelected && (
                  <div style={{
                    marginLeft: 280, padding: "12px 16px", background: C.card,
                    borderRadius: 8, marginBottom: 4, marginTop: 2, borderLeft: `3px solid ${phase?.color || C.accent}`,
                  }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                      <div>
                        <div style={{ fontSize: 11, color: C.textDim, marginBottom: 4 }}>
                          Fase {t.phase}: {phase?.name} · {MONTHS.find(m => m.key === t.startMonth)?.label} Semana {t.startWeek} · {t.duration} semanas
                        </div>
                        <div style={{ fontSize: 13, color: C.text, lineHeight: 1.5 }}>{t.notes || "Sin notas"}</div>
                      </div>
                      <button onClick={() => deleteTask(t.id)} style={{
                        background: "#ef444422", border: "1px solid #ef444444", color: "#ef4444",
                        padding: "4px 10px", borderRadius: 6, cursor: "pointer", fontSize: 11,
                      }}>Eliminar</button>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Legend */}
        <div style={{
          display: "flex", gap: 16, marginTop: 24, padding: 16, background: C.surface,
          borderRadius: 10, border: `1px solid ${C.border}`, flexWrap: "wrap", justifyContent: "center",
        }}>
          {Object.entries(CATEGORIES).map(([name, color]) => (
            <div key={name} style={{ display: "flex", alignItems: "center", gap: 6 }}>
              <div style={{ width: 10, height: 10, borderRadius: 3, background: color }} />
              <span style={{ fontSize: 11, color: C.textDim }}>{name}</span>
            </div>
          ))}
          <div style={{ width: 1, height: 16, background: C.border }} />
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <div style={{ width: 14, height: 14, borderRadius: 3, border: `2px solid ${C.accent}`, background: C.accent, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 8, color: C.bg, fontWeight: 700 }}>✓</div>
            <span style={{ fontSize: 11, color: C.textDim }}>Completada</span>
          </div>
        </div>
      </div>
    </div>
  );
}

