const initialTasks = [
  // Phase 1
  { id: 1, task: "Abrir cuenta Wise o Payoneer", phase: 1, cat: "Financiero", startMonth: 3, startWeek: 1, duration: 2, priority: "Alta", done: false, notes: "Para recibir payouts de prop firms" },
